/** 交付物名称 → 模板相对路径；未知名称返回 null（服务端以此为白名单，杜绝任意路径）。 */
export function getDeliverableTemplatePath(name: string): string | null {
  return DELIVERABLE_TEMPLATE_FILES[name] ?? null;
}
